typedef long long int ll;

const int S = 100010;



struct UnionFind {

  vector<int> node;

  vector<ll> weight;

  UnionFind() : node(S, -1), weight(S, 0) {}

  void unite(int u, int v, ll w) {

    int ov = v, ou = u;

    u = find(u), v = find(v);

    int wa = weight[ov], wb = weight[ou];

    if(u == v) return;



    // (v ??????) ??? (u ??????) ???????????????

    node[u] += node[v];

    node[v] = u;

    weight[v] += w + wb - wa;

  }



  int find(int u) {

    if(node[u] < 0) return u;

    int par = node[u], root = find(node[u]);

    weight[u] += weight[par];

    return node[u] = root;

  }

};



