int main()

{

    //freopen("i.txt","r",stdin);

    int n,t,last,ans2=0,ans1=0;

    scanf("%d",&n);

    priority_queue<int,vector<int>,greater<int> >r;

    priority_queue<int,vector<int>,less<int> >l;

    for(int i=0; i<n; i++)

    {

        scanf("%d %d",&a[i],&b[i]);

        s[a[i]]++,s[b[i]]--;

        l.push(a[i]),r.push(b[i]);

    }

    t=r.top(),r.pop();

    rr[last=t]=1;

    while(!r.empty())

    {

        t=r.top(),r.pop();

        rr[t]=rr[last]+1;

        last=t;

    }

    t=l.top(),l.pop();

    ll[last=t]=1;

    while(!l.empty())

    {

        t=l.top(),l.pop();

        ll[t]=ll[last]+1;

        last=t;

    }

    for(int i=1; i<=100000; i++)

        if(!rr[i])rr[i]=rr[i-1];

    for(int i=100000; i>=0; i--)

        if(!ll[i])ll[i]=ll[i+1];

    for(int i=0; i<n; i++)

        ans1=max(n-ll[b[i]]-rr[a[i]],ans1);

    for(int i=1; i<=100000; i++)

        ans2=max(s[i]=s[i-1]+s[i],ans2);

    printf("%d %d\n",ans1,ans2);

}

